//! Poseidon hash functions for Soroban contracts

use soroban_poseidon::poseidon_hash;
use soroban_sdk::{crypto::bn254::Bn254Fr, Bytes, Env, U256, Vec, vec};

/// Hash a pair of U256 values using Poseidon — matches circomlib Poseidon(2)
pub fn poseidon_compress(env: &Env, left: U256, right: U256) -> U256 {
    poseidon_hash::<3, Bn254Fr>(env, &vec![env, left, right])
}

/// Hash three U256 values using Poseidon — matches circomlib Poseidon(3)
pub fn poseidon_hash2(env: &Env, a: U256, b: U256, sep: Option<U256>) -> U256 {
    let sep = sep.unwrap_or_else(|| U256::from_u32(env, 0u32));
    poseidon_hash::<4, Bn254Fr>(env, &vec![env, a, b, sep])
}

